    water = 0

    # Forward pass
    max_height = L[0]
    for i in range(max_ind):
        if L[i] > max_height:
            max_height = L[i]
        else:
            water += max_height - L[i]

    # Backward pass
    max_height = L[-1]
    for i in range(N-1,max_ind,-1):
        if L[i] > max_height:
            max_height = L[i]
        else:
            water += max_height - L[i]

