class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        // your code goes here
        Scanner sc = new Scanner(System.in);

        int t = sc.nextInt();

        while(t-- > 0 ){
            int n = sc.nextInt();

            int a[] = new int[n];

            for (int i = 0 ; i < n ; i++ ) 
                a[i] = sc.nextInt();

            int left[] = new int[n];

            left[0] = a[0];

            for( int i = 1 ; i < n ; i++ ){
                left[i] = Math.max( left[i-1] , a[i] );
            }

            int right[] = new int[n];

            right[n-1] = a[n-1];

            for( int i = n-2 ; i >= 0 ; i-- ){
                right[i] = Math.max( right[i+1] , a[i] );
            }

            long ans = 0;

            for( int i = 0 ; i < n ; i++ ){
                ans += Math.min( left[i] , right[i] ) - a[i];
            }

            System.out.println( ans );
            //2 2 2 3
            //3 3 3 3
            //0 1 1 0
        }
    }
}
